function numberOfLists(num) {
    const mod = 1e9 + 7;
    const n = num.length;
    const dp = Array.from({ length: n + 1 }, () => Array(n + 1).fill(0));
    dp[0][0] = 1;

    for (let i = 0; i < n; ++i) {
        for (let j = 1; j <= n; ++j) {
            if (num[i] === '0') continue;
            for (let k = 1; i + k <= n; ++k) {
                if (k > 1 && num[i + k - 1] === '0') break;
                dp[i + k][j] = (dp[i + k][j] + dp[i][j - 1]) % mod;
            }
        }
    }

    let ans = 0;
    for (let i = 1; i <= n; ++i) {
        ans = (ans + dp[n][i]) % mod;
    }
    return ans;
}
```

