public int numberOfLists(String num) {
    int mod = 1000000007;
    int n = num.length();
    int[][] dp = new int[n + 1][n + 1];
    dp[0][0] = 1;

    for (int i = 0; i < n; ++i) {
        for (int j = 1; j <= n; ++j) {
            if (num.charAt(i) == '0') continue;
            for (int k = 1; i + k <= n; ++k) {
                if (k > 1 && num.charAt(i + k - 1) == '0') break;
                dp[i + k][j] = (dp[i + k][j] + dp[i][j - 1]) % mod;
            }
        }
    }

    int ans = 0;
    for (int i = 1; i <= n; ++i) {
        ans = (ans + dp[n][i]) % mod;
    }
    return ans;
}
```

